PREFIX  owl:  <http://www.w3.org/2002/07/owl#>
PREFIX  dc:   <http://purl.org/dc/elements/1.1/>

SELECT DISTINCT  ?president ?electionYear
WHERE
  {   { <http://rdf.freebase.com/ns/m.081pw>
                  <http://rdf.freebase.com/ns/time.event.start_date>  ?ww2Start ;
                  <http://rdf.freebase.com/ns/time.event.end_date>  ?ww2End .
        ?president  <http://rdf.freebase.com/ns/government.politician.government_positions_held>  ?pos .
        ?pos      <http://rdf.freebase.com/ns/government.government_position_held.office_position_or_title>  <http://rdf.freebase.com/ns/m.060d2> ;
                  <http://rdf.freebase.com/ns/government.government_position_held.from>  ?from ;
                  <http://rdf.freebase.com/ns/government.government_position_held.to>  ?to
        FILTER ( ?from < ?ww2End )
        FILTER ( ?to > ?ww2Start )
      }
    UNION
      { ?election1  <http://rdf.freebase.com/ns/government.election.winner>  <http://rdf.freebase.com/ns/m.03_js> ;
                  <http://rdf.freebase.com/ns/government.election.office>  <http://rdf.freebase.com/ns/m.060d2> ;
                  <http://rdf.freebase.com/ns/government.election.election_year>  ?electionYear
        BIND(<http://rdf.freebase.com/ns/m.03_js> AS ?president)
      }
    UNION
      { ?election2  <http://rdf.freebase.com/ns/government.election.winner>  <http://rdf.freebase.com/ns/m.034ls> ;
                  <http://rdf.freebase.com/ns/government.election.office>  <http://rdf.freebase.com/ns/m.060d2> ;
                  <http://rdf.freebase.com/ns/government.election.election_year>  ?electionYear
        BIND(<http://rdf.freebase.com/ns/m.034ls> AS ?president)
      }
  }

